const ltx23Models = $input.all()
  .map((item) => item.json)
  .filter((model) => {
    const id = String(model.id || '').toLowerCase();
    return id.startsWith('ltx23-') || id.startsWith('ltx2.3-');
  })
  .sort((a, b) => (b.workerCount || 0) - (a.workerCount || 0));

if (ltx23Models.length === 0) {
  throw new Error('No LTX 2.3 models are available right now. Try again later or open the video model dropdown to choose another family.');
}

const bestModel = ltx23Models[0];

return {
  json: {
    modelId: bestModel.id,
    modelName: bestModel.name || bestModel.id,
    workerCount: bestModel.workerCount || 0,
    recommendedSteps: bestModel.recommendedSettings?.steps || 20,
    recommendedGuidance: bestModel.recommendedSettings?.guidance || 3.5,
    frames: 113,
    fps: 24
  }
};
